input.onButtonPressed(Button.A, function () {
    logging = true
    basic.showIcon(IconNames.Yes)
    basic.pause(2000)
    basic.clearScreen()
    led.plot(0, 0)
})
input.onButtonPressed(Button.AB, function () {
    basic.showIcon(IconNames.Skull)
    datalogger.deleteLog()
    datalogger.setColumnTitles("water")
    basic.pause(2000)
    basic.clearScreen()
})
input.onButtonPressed(Button.B, function () {
    logging = false
    basic.showIcon(IconNames.No)
    basic.pause(2000)
    basic.clearScreen()
})
input.onLogoEvent(TouchButtonEvent.Pressed, function () {
    basic.showNumber(input.temperature())
    basic.pause(5000)
    basic.clearScreen()
})
let logging = false
logging = false
led.setBrightness(40)
datalogger.includeTimestamp(FlashLogTimeStampFormat.Minutes)
datalogger.setColumnTitles("water")
basic.forever(function () {
    if (logging) {
        if (input.pinIsPressed(TouchPin.P1)) {
            datalogger.log(datalogger.createCV("water", 1))
        } else {
            datalogger.log(datalogger.createCV("water", 0))
        }
        music.play(music.tonePlayable(523, music.beat(BeatFraction.Whole)), music.PlaybackMode.InBackground)
        basic.pause(15 * 60 * 1000)
    }
})
basic.forever(function () {
    if (input.pinIsPressed(TouchPin.P1)) {
        led.plot(0, 4)
    } else {
        led.unplot(0, 4)
    }
})
